import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import SpaceCard from '../components/SpaceCard';
import { useState, useEffect } from 'react';
import TourModal from '../components/TourModal';
import { Link } from 'react-router-dom';
import { getSpaces, getFilters } from '../services/spaceService';

// Import images
import heroImage from '../images/Home_page.jpg';
import workspace1 from '../images/austin-distel-wawEfYdpkag-unsplash.jpg';
import workspace2 from '../images/infralist-com-kmIKEGO7Vl4-unsplash.jpg';
import workspace3 from '../images/uneebo-office-design-UgYT5nkXdK4-unsplash.jpg';
import workspace4 from '../images/pawel-chu-ULh0i2txBCY-unsplash.jpg';
import workspace5 from '../images/suryadhityas-NrDZJ9oWV_Y-unsplash.jpg';
import workspace6 from '../images/running-a-successful-coworking-space-5aaa98c0bb414814ce745dc8.jpg';

const workspaceImages = [workspace1, workspace2, workspace3, workspace4, workspace5, workspace6];

export default function Home() {
  const [tourOpen, setTourOpen] = useState(false);
  const [spaces, setSpaces] = useState([]);
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [spacesData, filtersData] = await Promise.all([
          getSpaces({ limit: 6 }).catch(() => ({ data: [] })),
          getFilters().catch(() => ({ types: [] }))
        ]);
        setSpaces(spacesData.data || []);
        setTypes(filtersData.types || []);
      } catch (err) {
        console.error('Error loading home data:', err);
        setSpaces([]);
        setTypes([]);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar />
      <main className="flex-1">
        {/* Hero Section - Full Width with Image */}
        <section className="relative h-[90vh] min-h-[600px] flex items-center justify-center overflow-hidden">
          {/* Background Image */}
          <div className="absolute inset-0">
            <img
              src={heroImage}
              alt="Premium Workspace"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-r from-purple-900/90 via-pink-900/80 to-purple-900/90"></div>
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-gray-900/50"></div>
          </div>

          {/* Content */}
          <div className="relative z-10 max-w-full mx-auto px-6 md:px-12 lg:px-16 text-center text-white">
            <div className="inline-flex items-center gap-2 px-5 py-2.5 bg-white/10 backdrop-blur-xl border border-white/30 rounded-full mb-8 shadow-lg">
              <div className="w-2.5 h-2.5 bg-gradient-to-r from-purple-400 to-pink-400 rounded-full animate-pulse shadow-glow"></div>
              <span className="text-sm font-bold uppercase tracking-wider">Premium Workspaces</span>
            </div>

            <h1 className="text-5xl md:text-7xl lg:text-8xl font-extrabold mb-6 leading-tight">
              Find Your Perfect
              <span className="block bg-gradient-to-r from-purple-400 via-pink-400 to-purple-400 bg-clip-text text-transparent animate-gradient bg-size-200" style={{ backgroundSize: '200% 100%' }}>Workspace</span>
            </h1>

            <p className="text-xl md:text-2xl text-gray-200 mb-12 max-w-3xl mx-auto leading-relaxed font-medium">
              Discover and book premium coworking spaces that adapt to your needs, whenever and wherever you need them.
            </p>

            <div className="flex flex-col sm:flex-row gap-4 justify-center mb-16">
              <Link
                to="/search"
                className="px-10 py-4 bg-gradient-to-r from-purple-600 via-pink-600 to-purple-600 bg-size-200 bg-pos-0 hover:bg-pos-100 text-white font-bold rounded-xl transition-all duration-300 shadow-lg hover:shadow-glow-lg transform hover:-translate-y-1 active:translate-y-0 text-lg"
                style={{ backgroundSize: '200% 100%' }}
              >
                Explore Spaces
              </Link>
              <button
                onClick={() => setTourOpen(true)}
                className="px-10 py-4 bg-white/10 backdrop-blur-xl hover:bg-white/20 text-white font-bold rounded-xl border-2 border-white/30 hover:border-white/50 transition-all duration-300 shadow-lg hover:shadow-xl text-lg"
              >
                Book a Tour
              </button>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6 max-w-5xl mx-auto">
              {[
                { value: '12+', label: 'Cities' },
                { value: '1,200+', label: 'Spaces' },
                { value: '50k+', label: 'Bookings' },
                { value: '4.8/5', label: 'Rating' }
              ].map((stat, idx) => (
                <div key={idx} className="bg-white/10 backdrop-blur-xl border border-white/30 rounded-2xl p-6 hover:bg-white/15 transition-all duration-300 hover:scale-105 hover:shadow-glow">
                  <div className="text-4xl md:text-5xl font-extrabold mb-2 bg-gradient-to-r from-purple-300 to-pink-300 bg-clip-text text-transparent">{stat.value}</div>
                  <div className="text-sm text-gray-300 uppercase tracking-wider font-semibold">{stat.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Scroll Indicator */}
          <div className="absolute bottom-8 left-1/2 transform -translate-x-1/2 animate-bounce">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
            </svg>
          </div>
        </section>

        {/* Features Section */}
        <section className="py-24 bg-gradient-to-b from-white via-purple-50/30 to-white dark:from-gray-900 dark:via-purple-950/20 dark:to-gray-900">
          <div className="max-w-full mx-auto px-6 md:px-12 lg:px-16">
            <div className="text-center mb-20">
              <h2 className="text-4xl md:text-6xl font-extrabold text-gray-900 dark:text-white mb-6">
                Why Choose <span className="bg-gradient-to-r from-purple-600 to-pink-600 bg-clip-text text-transparent">WorkNest</span>
              </h2>
              <p className="text-xl text-gray-600 dark:text-gray-300 max-w-2xl mx-auto font-medium">
                Everything you need to discover, compare, and book flexible workspaces with confidence.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {[
                {
                  icon: '🔍',
                  title: 'Smart Search',
                  desc: 'Find the perfect workspace with advanced filters and real-time availability.',
                  gradient: 'from-purple-500 to-pink-500'
                },
                {
                  icon: '💳',
                  title: 'Transparent Pricing',
                  desc: 'Clear daily/hourly rates with no hidden fees or surprises.',
                  gradient: 'from-blue-500 to-purple-500'
                },
                {
                  icon: '🔒',
                  title: 'Secure Payments',
                  desc: 'PCI-compliant checkout with reliable invoicing and refunds.',
                  gradient: 'from-green-500 to-emerald-500'
                },
                {
                  icon: '⭐',
                  title: 'Verified Spaces',
                  desc: 'Curated listings with authentic photos and verified reviews.',
                  gradient: 'from-yellow-500 to-orange-500'
                },
                {
                  icon: '⏱️',
                  title: 'Real-time Availability',
                  desc: 'Accurate capacity and calendar slots to avoid conflicts.',
                  gradient: 'from-pink-500 to-rose-500'
                },
                {
                  icon: '💬',
                  title: '24/7 Support',
                  desc: 'Priority help for urgent changes, tours, or billing questions.',
                  gradient: 'from-indigo-500 to-purple-500'
                }
              ].map((feature, idx) => (
                <div
                  key={idx}
                  className="group relative p-8 bg-white/80 dark:bg-gray-800/80 backdrop-blur-xl rounded-2xl hover:shadow-2xl transition-all duration-300 border border-gray-200/50 dark:border-gray-700/50 hover:border-purple-300 dark:hover:border-purple-500 hover:-translate-y-2"
                >
                  <div className={`absolute top-0 left-0 w-full h-1 bg-gradient-to-r ${feature.gradient} rounded-t-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-300`}></div>
                  <div className={`w-16 h-16 rounded-2xl bg-gradient-to-br ${feature.gradient} flex items-center justify-center text-3xl mb-6 shadow-lg group-hover:scale-110 transition-transform duration-300`}>
                    <span>{feature.icon}</span>
                  </div>
                  <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-3 group-hover:text-purple-600 dark:group-hover:text-purple-400 transition-colors">{feature.title}</h3>
                  <p className="text-gray-600 dark:text-gray-300 leading-relaxed">{feature.desc}</p>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* Workspace Types Gallery */}
        <section className="py-24 bg-gradient-to-b from-white to-gray-50 dark:from-gray-900 dark:to-gray-950">
          <div className="max-w-full mx-auto px-6 md:px-12 lg:px-16">
            <div className="text-center mb-20">
              <h2 className="text-4xl md:text-6xl font-extrabold text-gray-900 dark:text-white mb-6">
                Explore by <span className="bg-gradient-to-r from-purple-600 to-pink-600 bg-clip-text text-transparent">Type</span>
              </h2>
              <p className="text-xl text-gray-600 dark:text-gray-300 font-medium">Find the workspace solution that fits your needs</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {loading ? (
                <div className="col-span-full text-center py-8">
                  <svg className="animate-spin h-8 w-8 text-blue-600 mx-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                </div>
              ) : types.length === 0 ? (
                <div className="col-span-full text-center py-8 text-gray-500">No workspace types available</div>
              ) : (
                types.map((type, idx) => {
                  const imageIndex = idx % workspaceImages.length;
                  return (
                    <Link
                      key={type}
                      to="/search"
                      className="group relative h-72 rounded-3xl overflow-hidden shadow-xl hover:shadow-2xl transition-all duration-500 transform hover:-translate-y-3 hover:scale-[1.02]"
                    >
                      <img
                        src={workspaceImages[imageIndex]}
                        alt={type}
                        className="w-full h-full object-cover group-hover:scale-125 transition-transform duration-700"
                      />
                      <div className="absolute inset-0 bg-gradient-to-t from-purple-900/90 via-pink-900/60 to-transparent group-hover:from-purple-900/95 group-hover:via-pink-900/70 transition-all duration-500"></div>
                      <div className="absolute bottom-0 left-0 right-0 p-8">
                        <h3 className="text-3xl font-extrabold text-white mb-3 group-hover:text-purple-200 transition-colors">{type}</h3>
                        <div className="flex items-center text-white text-base font-semibold">
                          <span>Explore</span>
                          <svg className="w-5 h-5 ml-2 group-hover:translate-x-2 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
                          </svg>
                        </div>
                      </div>
                      <div className="absolute top-4 right-4 w-12 h-12 rounded-xl bg-white/20 backdrop-blur-md border border-white/30 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                        <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                        </svg>
                      </div>
                    </Link>
                  );
                })
              )}
            </div>
          </div>
        </section>

        {/* Featured Spaces */}
        <section className="py-20 bg-white dark:bg-gray-800">
          <div className="max-w-full mx-auto px-6 md:px-12 lg:px-16">
            <div className="flex items-center justify-between mb-12">
              <div>
                <h2 className="text-4xl md:text-5xl font-bold text-gray-900 dark:text-white mb-4">Featured Spaces</h2>
                <p className="text-lg text-gray-600 dark:text-gray-300">Handpicked premium workspaces</p>
              </div>
              <Link
                to="/search"
                className="text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-semibold flex items-center gap-2"
              >
                View All
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                </svg>
              </Link>
            </div>

            {loading ? (
              <div className="text-center py-12">
                <svg className="animate-spin h-12 w-12 text-blue-600 mx-auto" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                <p className="mt-4 text-gray-600">Loading featured spaces...</p>
              </div>
            ) : spaces.length === 0 ? (
              <div className="text-center py-12 text-gray-500">No featured spaces available</div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {spaces.map((space) => (
                  <div key={space._id || space.id}>
                    <SpaceCard space={space} />
                  </div>
                ))}
              </div>
            )}
          </div>
        </section>

        {/* CTA Section */}
        <section className="py-20 bg-gradient-to-r from-blue-600 to-indigo-700">
          <div className="max-w-full mx-auto px-6 md:px-12 lg:px-16 text-center text-white">
            <h2 className="text-4xl md:text-5xl font-bold mb-6">Ready to Find Your Workspace?</h2>
            <p className="text-xl text-blue-100 mb-10">
              Join thousands of teams using WorkNest to work better, together.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <Link
                to="/search"
                className="px-8 py-4 bg-white text-blue-600 hover:bg-gray-100 font-semibold rounded-lg transition-all duration-200 shadow-lg"
              >
                Start Searching
              </Link>
              <button
                onClick={() => setTourOpen(true)}
                className="px-8 py-4 bg-white/10 backdrop-blur-md hover:bg-white/20 text-white font-semibold rounded-lg border border-white/20 transition-all duration-200"
              >
                Schedule a Tour
              </button>
            </div>
          </div>
        </section>

        <TourModal open={tourOpen} onClose={() => setTourOpen(false)} />
      </main>
      <Footer />
    </div>
  );
}
